DROP TABLE IF EXISTS `fees_records`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `fees_records` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `student_id` int(11) NOT NULL,
  `fees_type` int(11) NOT NULL COMMENT '0:school fees,1:extra fees',
  `amount` double NOT NULL,
  `fees_id` int(11) NOT NULL,
  `apiId` int(11) DEFAULT NULL,
  `refNo` varchar(50) DEFAULT NULL,
  `payment_mode` int(11) NOT NULL DEFAULT 1,
  `due_date` date NOT NULL,
  `status` int(11) NOT NULL DEFAULT 1 COMMENT '-1:cancelled,1:normal',
  `created_by` int(11) NOT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `student_id` (`student_id`,`fees_type`,`refNo`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

